        param_idx = 1

        parts = [f"UPDATE {self._update_table}"]

        # SET
        set_parts = []
        for col, val in self._update_sets.items():
            set_parts.append(f"{col} = ${param_idx}")
            params.append(val)
            param_idx += 1
        parts.append(f"SET {', '.join(set_parts)}")

